const item = $input.item.json;
const telefono = String(item.telefono || '').replace(/[^\d]/g, '');
const texto = String(item.texto || '').trim().slice(0, 4000);
const fecha = new Date().toISOString().split('T')[0];
if (!telefono || !texto) {
  return { ok: false, error: 'falta telefono o texto' };
}
return { telefono, texto, fecha };

const ctx = $input.item.json;
const usuarias = $('fetch usuaria').all().map(i => i.json);
const u = usuarias[0];
let fase = null;
if (u && u.fecha_inicio_ciclo) {
  const lastPeriod = new Date(u.fecha_inicio_ciclo);
  const cycleLength = u.promedio_duracion_ciclo || u.duracion_ciclo || 28;
  const today = new Date(ctx.fecha + 'T00:00:00');
  const diffDays = Math.max(0, Math.floor((today - lastPeriod) / (1000*60*60*24)));
  const day = (diffDays % cycleLength) + 1;
  const ovulation = Math.max(8, cycleLength - 14);
  if (day <= 5) fase = 'menstrual';
  else if (day < ovulation - 2) fase = 'folicular';
  else if (day <= ovulation + 2) fase = 'ovulatoria';
  else fase = 'lutea';
}
return { ...ctx, fase };
